package se.medbo.examplatform.ai.question;

import static se.medbo.examplatform.ai.question.QuestionIntelligenceAssessment.*;
import java.time.OffsetDateTime;
import java.util.ArrayList;
import java.util.EnumMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.regex.Pattern;

@org.springframework.stereotype.Component
final class QuestionIntelligenceEngine {
  private static final String VALIDATOR_VERSION="1";
  private static final Pattern HTML=Pattern.compile("<[^>]+>");
  private static final Pattern URL=Pattern.compile("(?i)https?://|www\\.");
  private static final Pattern MARKDOWN=Pattern.compile("(?m)^(#{1,6}\\s|```)|\\[[^]]+]\\([^)]+\\)");
  private static final Pattern SQL=Pattern.compile("(?i)\\b(select|insert|update|delete|drop)\\s+(from|into|table|[a-z_]+\\s+set)\\b");
  private static final Pattern INJECTION=Pattern.compile("(?i)(ignore (all|any|the)? ?previous instructions|system prompt|developer message|publish (this|the)|approve (this|the)|call another service|use information from the internet)");
  private static final Pattern EMOJI=Pattern.compile("[\\x{1F300}-\\x{1FAFF}]");
  private final QuestionIntelligencePolicy policy;
  QuestionIntelligenceEngine(QuestionIntelligencePolicy policy){this.policy=policy;}

  record Context(boolean groundingPassed,OffsetDateTime evaluatedAt,String language,GenerationIntent intent) {}

  QuestionIntelligenceAssessment assess(QuestionGenerationProviderClient.Proposal p,Context context){
    var findings=new ArrayList<Finding>();var scores=new EnumMap<Component,Integer>(Component.class);for(var component:Component.values())scores.put(component,100);
    textChecks(p,findings,scores);optionChecks(p,findings,scores);explanationChecks(p,findings,scores);languageAndGrounding(p,context,findings,scores);
    Metadata metadata=metadata(p,context,findings,scores);int score=weighted(scores);boolean passed=findings.stream().noneMatch(Finding::blocking);QualityLevel level=passed?level(score):QualityLevel.REJECTED;
    var blocked=findings.stream().filter(Finding::blocking).toList();var warnings=findings.stream().filter(f->!f.blocking()&&f.severity()==Severity.WARNING).toList();var info=findings.stream().filter(f->f.severity()==Severity.INFO).toList();
    return new QuestionIntelligenceAssessment(score,level,passed,blocked,warnings,info,metadata,Map.copyOf(scores),context.evaluatedAt(),policy.engineVersion,safeRationale(p.qualityRationale()));
  }
  private void textChecks(QuestionGenerationProviderClient.Proposal p,List<Finding> f,Map<Component,Integer>s){String q=p.questionText()==null?"":p.questionText().trim();int words=words(q);if(q.isBlank())block(f,s,Component.STRUCTURE,"QUESTION_TEXT_MISSING",Category.STRUCTURE,"Question text is required.","questionText","QuestionTextPresentValidator");if(words<policy.shortQuestionWords)warn(f,s,Component.READABILITY,10,"QUESTION_WORDING_VERY_SHORT",Category.READABILITY,"The question may be too short to be clear.","questionText","QuestionLengthValidator");if(words>policy.longQuestionWords)warn(f,s,Component.READABILITY,15,"QUESTION_WORDING_SLIGHTLY_LONG",Category.READABILITY,"The question may be longer than necessary.","questionText","QuestionLengthValidator");if(words>policy.maximumQuestionWords)block(f,s,Component.READABILITY,"QUESTION_WORDING_EXCESSIVE",Category.READABILITY,"The question exceeds the supported length.","questionText","QuestionLengthValidator");if(count(q,'?')>1)warn(f,s,Component.STRUCTURE,15,"MULTIPLE_QUESTIONS_LIKELY",Category.STRUCTURE,"The stem may contain more than one question.","questionText","MultipleQuestionValidator");if(HTML.matcher(q).find())block(f,s,Component.STRUCTURE,"HTML_CONTENT",Category.SECURITY,"HTML is not allowed in question text.","questionText","HtmlContentValidator");if(MARKDOWN.matcher(q).find())block(f,s,Component.STRUCTURE,"MARKDOWN_CONTENT",Category.SECURITY,"Markdown fragments are not allowed in question text.","questionText","MarkdownFragmentValidator");if(URL.matcher(q).find())block(f,s,Component.STRUCTURE,"URL_CONTENT",Category.SECURITY,"URLs are not allowed in question text.","questionText","UrlContentValidator");if(SQL.matcher(q).find())block(f,s,Component.STRUCTURE,"SQL_CONTENT",Category.SECURITY,"Executable-looking SQL is not allowed in question text.","questionText","SecurityContentValidator");if(INJECTION.matcher(q).find())block(f,s,Component.STRUCTURE,"PROMPT_INJECTION",Category.SECURITY,"Embedded provider or publication instructions are not allowed.","questionText","PromptInjectionValidator");if(EMOJI.matcher(q).find())warn(f,s,Component.READABILITY,10,"EMOJI_CONTENT",Category.STYLE,"Emoji may reduce assessment clarity.","questionText","EmojiValidator");if(q.matches(".*[!?]{3,}.*"))warn(f,s,Component.READABILITY,10,"EXCESSIVE_PUNCTUATION",Category.STYLE,"Repeated punctuation should be removed.","questionText","ExcessivePunctuationValidator");String letters=q.replaceAll("[^\\p{L}]","");if(letters.length()>8&&letters.equals(letters.toUpperCase(Locale.ROOT)))warn(f,s,Component.READABILITY,15,"ALL_CAPS",Category.STYLE,"Avoid writing the question in all capital letters.","questionText","AllCapsValidator");String n=QuestionProposalValidator.normalize(q);long negatives=List.of(" inte "," ingen "," inget "," inga "," aldrig ").stream().filter(x->(" "+n+" ").contains(x)).count();if(negatives==1)warn(f,s,Component.READABILITY,5,"NEGATIVE_WORDING",Category.READABILITY,"Negative wording may make the question harder to interpret.","questionText","DoubleNegativeValidator");if(negatives>1)warn(f,s,Component.READABILITY,20,"DOUBLE_NEGATIVE_LIKELY",Category.READABILITY,"The question may contain a double negative.","questionText","DoubleNegativeValidator");}
  private void optionChecks(QuestionGenerationProviderClient.Proposal p,List<Finding>f,Map<Component,Integer>s){var options=p.answerOptions()==null?List.<QuestionGenerationProviderClient.Option>of():p.answerOptions();if(options.size()<2||options.size()>6)block(f,s,Component.STRUCTURE,"OPTION_COUNT_INVALID",Category.STRUCTURE,"Question type requires a supported number of options.","answerOptions","OptionCountValidator");var normalized=new java.util.HashSet<String>();int correct=0;for(var option:options){if(option.text()==null||option.text().isBlank())block(f,s,Component.COMPLETENESS,"OPTION_TEXT_MISSING",Category.COMPLETENESS,"Every answer option requires text.","answerOptions","OptionCountValidator");else{if(!normalized.add(QuestionProposalValidator.normalize(option.text())))block(f,s,Component.STRUCTURE,"DUPLICATE_OPTION",Category.STRUCTURE,"Answer options must be unique.","answerOptions","DuplicateOptionValidator");if(words(option.text())>policy.maximumOptionWords)warn(f,s,Component.READABILITY,10,"OPTION_WORDING_LONG",Category.READABILITY,"An answer option may be longer than necessary.","answerOptions","QuestionLengthValidator");}if(option.correct())correct++;}boolean valid="MULTIPLE_CHOICE".equals(p.questionType())?correct>0&&correct<options.size():correct==1;if(!valid)block(f,s,Component.STRUCTURE,"CORRECT_ANSWER_CARDINALITY_INVALID",Category.STRUCTURE,"Correct-answer cardinality does not match the question type.","answerOptions","CorrectAnswerCardinalityValidator");}
  private void explanationChecks(QuestionGenerationProviderClient.Proposal p,List<Finding>f,Map<Component,Integer>s){int count=words(p.explanation());if(p.explanation()==null||p.explanation().isBlank())block(f,s,Component.COMPLETENESS,"EXPLANATION_MISSING",Category.COMPLETENESS,"An explanation is required.","explanation","ExplanationPresentValidator");else if(count<policy.minimumExplanationWords)warn(f,s,Component.COMPLETENESS,15,"EXPLANATION_SHORT",Category.COMPLETENESS,"The explanation may be too short.","explanation","ExplanationConsistencyValidator");else if(count>policy.maximumExplanationWords)warn(f,s,Component.COMPLETENESS,15,"EXPLANATION_LONG",Category.COMPLETENESS,"The explanation may be longer than necessary.","explanation","ExplanationConsistencyValidator");}
  private void languageAndGrounding(QuestionGenerationProviderClient.Proposal p,Context c,List<Finding>f,Map<Component,Integer>s){if(!c.groundingPassed())block(f,s,Component.GROUNDING,"GROUNDING_REQUIRED",Category.GROUNDING,"Existing grounding validation must pass.","evidence","ExistingGroundingResultValidator");if(!List.of("sv","en").contains(c.language().toLowerCase(Locale.ROOT)))block(f,s,Component.READABILITY,"UNSUPPORTED_LANGUAGE",Category.LANGUAGE,"The proposal language is unsupported.","language","LanguageConsistencyValidator");if(!c.language().equalsIgnoreCase(p.language()))block(f,s,Component.READABILITY,"LANGUAGE_MISMATCH",Category.LANGUAGE,"Question content does not match the requested language.","language","LanguageConsistencyValidator");}
  private Metadata metadata(QuestionGenerationProviderClient.Proposal p,Context c,List<Finding>f,Map<Component,Integer>s){var provider=p.metadata();Difficulty pd=parse(Difficulty.class,provider==null?null:provider.difficulty(),"difficulty",f,s);BloomsLevel pb=parse(BloomsLevel.class,provider==null?null:provider.bloomsLevel(),"bloomsLevel",f,s);Complexity pc=parse(Complexity.class,provider==null?null:provider.complexity(),"complexity",f,s);GenerationIntent pi=parse(GenerationIntent.class,provider==null?null:provider.intent(),"intent",f,s);int reading=readingSeconds(p);Complexity derivedComplexity=deriveComplexity(p,reading);BloomsLevel derivedBloom=deriveBloom(p);Difficulty derivedDifficulty=deriveDifficulty(p,derivedBloom,derivedComplexity,reading);if(pd==null)warn(f,s,Component.METADATA_CONSISTENCY,10,"DIFFICULTY_INFERRED",Category.METADATA,"Difficulty was inferred by the application.","metadata.difficulty","DifficultyConsistencyValidator");else if(distance(pd,derivedDifficulty)>1)warn(f,s,Component.METADATA_CONSISTENCY,15,"DIFFICULTY_MISMATCH",Category.METADATA,"Provider difficulty differs from deterministic signals.","metadata.difficulty","DifficultyConsistencyValidator");if(pb==null)warn(f,s,Component.METADATA_CONSISTENCY,10,"BLOOM_LEVEL_INFERRED",Category.METADATA,"Bloom level was inferred by the application.","metadata.bloomsLevel","BloomConsistencyValidator");else if(pb.ordinal()>=BloomsLevel.EVALUATE.ordinal()&&derivedBloom.ordinal()<=BloomsLevel.UNDERSTAND.ordinal())warn(f,s,Component.METADATA_CONSISTENCY,25,"BLOOM_LEVEL_MISMATCH",Category.METADATA,"The proposed Bloom level is not supported by this question structure.","metadata.bloomsLevel","BloomConsistencyValidator");if(pc!=null&&pc!=derivedComplexity)warn(f,s,Component.METADATA_CONSISTENCY,10,"COMPLEXITY_MISMATCH",Category.METADATA,"Provider complexity differs from deterministic complexity.","metadata.complexity","ComplexityConsistencyValidator");if(provider!=null&&provider.estimatedReadingSeconds()!=null&&Math.abs(provider.estimatedReadingSeconds()-reading)>10)warn(f,s,Component.METADATA_CONSISTENCY,5,"READING_TIME_MISMATCH",Category.METADATA,"Provider reading time differs from the deterministic estimate.","metadata.estimatedReadingSeconds","ReadingTimeEstimator");if(pi!=null&&pi!=GenerationIntent.PRACTICE)warn(f,s,Component.METADATA_CONSISTENCY,10,"INTENT_DEFAULTED",Category.METADATA,"Generation intent is fixed to PRACTICE in this phase.","metadata.intent","MetadataEnumValidator");return new Metadata(derivedDifficulty,derivedBloom,derivedComplexity,GenerationIntent.PRACTICE,reading,pd,pb,pc,provider==null?null:provider.estimatedReadingSeconds());}
  private int readingSeconds(QuestionGenerationProviderClient.Proposal p){int wordCount=words(p.questionText())+(p.answerOptions()==null?0:p.answerOptions().stream().mapToInt(o->words(o.text())).sum());return Math.max(policy.minimumReadingSeconds,(int)Math.ceil(wordCount*60.0/policy.wordsPerMinute));}
  private Complexity deriveComplexity(QuestionGenerationProviderClient.Proposal p,int reading){int clauses=p.questionText()==null?0:p.questionText().split("[,;:]|\\b(och|eller|men|som)\\b").length;return reading>30||clauses>4?Complexity.HIGH:reading>15||clauses>2?Complexity.MEDIUM:Complexity.LOW;}
  private BloomsLevel deriveBloom(QuestionGenerationProviderClient.Proposal p){String q=QuestionProposalValidator.normalize(p.questionText());return q.matches(".*\\b(varfor|hur|skillnad|innebar|betyder)\\b.*")?BloomsLevel.UNDERSTAND:BloomsLevel.REMEMBER;}
  private Difficulty deriveDifficulty(QuestionGenerationProviderClient.Proposal p,BloomsLevel bloom,Complexity complexity,int reading){int value=(bloom.ordinal()+complexity.ordinal()+("MULTIPLE_CHOICE".equals(p.questionType())?1:0)+(reading>25?1:0));return value<=1?Difficulty.EASY:value<=3?Difficulty.MEDIUM:value<=5?Difficulty.HARD:Difficulty.VERY_HARD;}
  private int weighted(Map<Component,Integer>s){return clamp((s.get(Component.GROUNDING)*policy.groundingWeight+s.get(Component.STRUCTURE)*policy.structureWeight+s.get(Component.READABILITY)*policy.readabilityWeight+s.get(Component.COMPLETENESS)*policy.completenessWeight+s.get(Component.METADATA_CONSISTENCY)*policy.metadataWeight)/100);}
  private QualityLevel level(int score){return score>=policy.excellentThreshold?QualityLevel.EXCELLENT:score>=policy.goodThreshold?QualityLevel.GOOD:score>=policy.acceptableThreshold?QualityLevel.ACCEPTABLE:QualityLevel.NEEDS_REVIEW;}
  private <E extends Enum<E>>E parse(Class<E> type,String value,String field,List<Finding>f,Map<Component,Integer>s){if(value==null||value.isBlank())return null;try{return Enum.valueOf(type,value);}catch(IllegalArgumentException e){block(f,s,Component.METADATA_CONSISTENCY,"METADATA_ENUM_INVALID",Category.METADATA,"Provider returned unsupported "+field+" metadata.","metadata."+field,"MetadataEnumValidator");return null;}}
  private int distance(Enum<?>a,Enum<?>b){return Math.abs(a.ordinal()-b.ordinal());}private int words(String v){String n=QuestionProposalValidator.normalize(v);return n.isBlank()?0:n.split(" ").length;}private int count(String v,char c){int n=0;for(char x:v.toCharArray())if(x==c)n++;return n;}private int clamp(int n){return Math.max(0,Math.min(100,n));}private String safeRationale(String r){return r==null?null:r.substring(0,Math.min(500,r.length())).trim();}
  private void block(List<Finding>f,Map<Component,Integer>s,Component component,String code,Category category,String message,String field,String validator){s.put(component,0);f.add(finding(code,Severity.ERROR,category,message,field,true,validator));}
  private void warn(List<Finding>f,Map<Component,Integer>s,Component component,int penalty,String code,Category category,String message,String field,String validator){s.put(component,clamp(s.get(component)-penalty));f.add(finding(code,Severity.WARNING,category,message,field,false,validator));}
  private Finding finding(String code,Severity severity,Category category,String message,String field,boolean blocking,String validator){return new Finding(code,severity,category,message,field,blocking,new LinkedHashMap<>(),validator,VALIDATOR_VERSION);}
}
